const items = $input.all();

return items.map(item => {
  // Check if binary data exists
  if (!item.binary || !item.binary.data) {
    // Try to get path from json instead
    const jsonPath = item.json?.filePath || item.json?.path;
    if (jsonPath) {
      // Convert path even without binary
      const windowsPath = jsonPath
        .replace('cloned-site', 'uk-site')
        .replace(/^\/host\/([a-z])\//, (match, drive) => `${drive.toUpperCase()}:\\`)
        .replace(/\//g, '\\');

      return {
        json: {
          filePath: windowsPath,
          sourcePath: jsonPath
            .replace(/^\/host\/([a-z])\//, (match, drive) => `${drive.toUpperCase()}:\\`)
            .replace(/\//g, '\\')
        },
        binary: item.binary
      };
    }
    return item;
  }

  const binary = item.binary.data;

  // Try multiple ways to get directory and fileName
  const directory = binary.directory || item.json?.directory || '';
  const fileName = binary.fileName || item.json?.fileName || '';

  if (!directory || !fileName) {
    // Fallback: extract from filePath
    const filePath = item.json?.filePath || item.json?.path || '';
    if (filePath) {
      const windowsPath = filePath
        .replace('cloned-site', 'uk-site')
        .replace(/^\/host\/([a-z])\//, (match, drive) => `${drive.toUpperCase()}:\\`)
        .replace(/\//g, '\\');

      return {
        json: {
          filePath: windowsPath,
          sourcePath: filePath
            .replace(/^\/host\/([a-z])\//, (match, drive) => `${drive.toUpperCase()}:\\`)
            .replace(/\//g, '\\')
        },
        binary: { data: binary }
      };
    }
    return item;
  }

  // Your original logic
  const newPath = directory
    .replace('cloned-site', 'uk-site') + '/' + fileName;

  const windowsPath = newPath
    .replace(/^\/host\/([a-z])\//, (match, drive) => `${drive.toUpperCase()}:\\`)
    .replace(/\//g, '\\');

  const sourcePath = directory + '/' + fileName;
  const windowsSourcePath = sourcePath
    .replace(/^\/host\/([a-z])\//, (match, drive) => `${drive.toUpperCase()}:\\`)
    .replace(/\//g, '\\');

  return {
    json: {
      filePath: windowsPath,
      sourcePath: windowsSourcePath
    },
    binary: { data: binary }
  };
});

const item = $input.item;
const binary = item.binary?.data;

if (!binary) return [];

const fs = require('fs');

const filePath = binary.directory 
  ? `${binary.directory}/${binary.fileName}` 
  : binary.fileName;

const htmlContent = fs.readFileSync(filePath, 'utf-8');

return [{
  json: {
    html: htmlContent,
    fileName: binary.fileName || 'unknown.html',
    filePath: filePath,
    fileExtension: binary.fileExtension || 'html',
    mimeType: binary.mimeType || 'text/html'
  }
}];

const item = $input.item;
const html = $json.html || '';
const fileName = $json.fileName || $json.filePath?.split('/').pop() || 'output.html';

return [{
  json: {
    filePath: $json.filePath,
    fileName: fileName
  },
  binary: {
    data: {
      data: Buffer.from(html, 'utf-8').toString('base64'),
      mimeType: 'text/html',
      fileName: fileName,
      fileExtension: 'html'
    }
  }
}];

// ============================================================
//  INJECTION NODE — Localization Agent v2
//  Injects rewritten text back into original HTML.
//  MUST use identical skip rules as the extraction node.
// ============================================================

const cheerio = require('cheerio');
const item = $input.item;

const original      = $json.originalHtml || '';
const expectedCount = $json.lineCount    || 0;
const rawRewritten  = $json.text         || '';   // LLM output from Basic LLM Chain

// ── Parse LLM output ──
// Format: N|||FLAG:::rewritten text
// Normalise escaped newlines and split into lines
const rewrittenLines = rawRewritten
  .replace(/\\n/g, '\n')
  .split('\n')
  .filter(l => l.trim() !== '');

// Extract the text part after FLAG:::
const newTexts = rewrittenLines.map(line => {
  // Match: number|||FLAG:::text
  const match = line.match(/^\d+\|\|\|(?:TRANSLATE|PROTECT):::(.*)$/);
  if (match) return match[1];
  // Fallback: if LLM dropped the prefix somehow, try old format N|||text
  const fallback = line.match(/^\d+\|\|\|(.*)$/);
  if (fallback) return fallback[1];
  return null;
}).filter(t => t !== null);

// ── Mismatch guard ──
if (expectedCount > 0 && newTexts.length !== expectedCount) {
  return {
    json: {
      filePath: $json.filePath,
      html:     original,           // return original HTML untouched
      warning:  `MISMATCH: expected ${expectedCount} lines, got ${newTexts.length}. Original HTML returned.`,
      success:  false,
    },
    binary: item.binary,
  };
}

// ── Load HTML — same decodeEntities setting as extraction ──
const $ = cheerio.load(original, { decodeEntities: false });

// ── Identical skip rules as extraction node ──
const SKIP_TAGS = new Set([
  'script', 'style', 'noscript',
  'svg', 'path', 'defs', 'marker', 'circle', 'rect', 'line',
  'polyline', 'polygon', 'ellipse', 'text', 'tspan', 'g', 'use',
  'symbol', 'clippath', 'lineargradient', 'radialgradient',
  'stop', 'pattern', 'image', 'filter',
  'fegaussianblur', 'fecolormatrix', 'feblend', 'fecomposite',
]);

// ── Collect text nodes in exactly the same order as extraction ──
const textNodes = [];

$('body *').contents().each(function () {
  const parent = this.parent;
  const parentTag = parent && parent.name ? parent.name.toLowerCase() : '';

  if (SKIP_TAGS.has(parentTag)) return;
  if (this.type !== 'text') return;

  const raw = this.data || '';
  if (!raw.trim()) return;

  const text = raw.replace(/\s+/g, ' ').trim();
  if (!text) return;

  // <a> handling — same rule as extraction
  if (parentTag === 'a') {
    const href  = (parent.attribs && parent.attribs.href)  || '';
    const cls   = (parent.attribs && parent.attribs.class) || '';
    if (
      href.startsWith('http')    ||
      href.startsWith('mailto')  ||
      href.startsWith('//')      ||
      cls.includes('__cf_email__')
    ) return;
  }

  textNodes.push(this);
});

// ── Inject: replace each text node's data with the rewritten version ──
for (let i = 0; i < textNodes.length; i++) {
  if (i < newTexts.length && newTexts[i] !== null) {
    // Preserve any leading/trailing whitespace the original node had
    const originalRaw   = textNodes[i].data;
    const leadingSpace  = originalRaw.match(/^\s*/)[0];
    const trailingSpace = originalRaw.match(/\s*$/)[0];
    textNodes[i].data   = leadingSpace + newTexts[i] + trailingSpace;
  }
}

// ── Fix relative asset paths (./  →  /) ──
$('link, script, img, source, video').each((i, el) => {
  const attrs = $(el).is('link') ? ['href'] : ['src', 'href'];
  attrs.forEach(attr => {
    let val = $(el).attr(attr);
    if (!val) return;
    if (val.startsWith('http') || val.startsWith('data:') || val.startsWith('//')) return;
    if (val.startsWith('./')) $(el).attr(attr, val.slice(1));
  });
});

return {
  json: {
    filePath: $json.filePath,
    html:     $.html(),
    warning:  null,
    success:  true,
  },
  binary: item.binary,
};

const items = $input.all();

return items.map(item => {
  // Case 1: HTML files (from JSON → Binary node)
  if (item.binary && item.binary.data) {
    const binary = item.binary.data;
    const filePath = item.json.filePath;

    // Convert Docker path to Windows path
    const dockerPath = filePath
      .replace('cloned-site', 'uk-site');

    const windowsPath = dockerPath
      .replace(/^\/host\/([a-z])\//, (match, drive) => `${drive.toUpperCase()}:\\`)
      .replace(/\//g, '\\');

    return {
      json: {
        filePath: windowsPath
      },
      binary: { 
        data: binary 
      }
    };
  }

  // Case 2: Asset files (JS, CSS, Images - from false branch)
  // Need to create binary data from originalHtml or pass through
  else if (item.json && item.json.filePath) {
    const filePath = item.json.filePath;
    const html = item.json.originalHtml || item.json.html || '';

    // Determine file extension from filePath
    const fileExtension = filePath.split('.').pop().toLowerCase();
    let mimeType = 'text/html';

    if (fileExtension === 'js') mimeType = 'application/javascript';
    else if (fileExtension === 'css') mimeType = 'text/css';
    else if (fileExtension === 'json') mimeType = 'application/json';
    else if (['png', 'jpg', 'jpeg', 'gif', 'svg'].includes(fileExtension)) {
      mimeType = `image/${fileExtension === 'jpg' ? 'jpeg' : fileExtension}`;
    }

    // Convert to Windows path
    const dockerPath = filePath
      .replace('cloned-site', 'uk-site');

    const windowsPath = dockerPath
      .replace(/^\/host\/([a-z])\//, (match, drive) => `${drive.toUpperCase()}:\\`)
      .replace(/\//g, '\\');

    // Create binary data if we have HTML/content
    if (html) {
      return {
        json: {
          filePath: windowsPath
        },
        binary: {
          data: {
            data: Buffer.from(html, 'utf-8').toString('base64'),
            mimeType: mimeType,
            fileName: filePath.split('/').pop(),
            fileExtension: fileExtension
          }
        }
      };
    }

    // No content, just fix the path
    return {
      json: {
        filePath: windowsPath
      }
    };
  }

  // Case 3: Pass through unchanged
  return item;
});

// ============================================================
//  EXTRACTION NODE — Localization Agent v2.1
//  Auto-detects PROTECT items so the LLM prompt needs zero hardcoding.
// ============================================================

const cheerio = require('cheerio');
const item = $input.item;

const html =
  $json.html ||
  $json.data ||
  Buffer.from(item.binary?.data?.data || '', 'base64').toString('utf8');

const $ = cheerio.load(html, { decodeEntities: false });

// ── Tags whose text must NEVER be touched ──
const SKIP_TAGS = new Set([
  'script', 'style', 'noscript',
  'svg', 'path', 'defs', 'marker', 'circle', 'rect', 'line',
  'polyline', 'polygon', 'ellipse', 'text', 'tspan', 'g', 'use',
  'symbol', 'clippath', 'lineargradient', 'radialgradient',
  'stop', 'pattern', 'image', 'filter',
  'fegaussianblur', 'fecolormatrix', 'feblend', 'fecomposite',
]);

// ── Auto-detect PROTECT rules (no hardcoding) ──
function getFlag(text, parentTag) {

  // 1. Pure numeric stats: 10+, 50k+, 99%, 24/7, 100+
  if (/^\d+[k+%]?\d*\+?$/.test(text))         return 'PROTECT';
  if (/^\d+\/\d+$/.test(text))                 return 'PROTECT'; // e.g. 24/7

  // 2. Copyright lines
  if (/^Copyright\s*©/.test(text))             return 'PROTECT';

  // 3. Pure UI symbols
  if (/^[<>|·•\-–—/\\]+$/.test(text))         return 'PROTECT';

  // 4. Browser fallback text
  if (/^Your browser does not support/.test(text)) return 'PROTECT';

  // 5. Dropdown/nav tech labels (single-word or known compound tech names)
  //    Detect: text is a single token with no spaces,
  //    OR known compound tech patterns — all caps acronyms, version numbers,
  //    registered marks, camelCase product names
  if (/^[A-Z][a-zA-Z0-9]*(\s[A-Z][a-zA-Z0-9]*)*[®™]?$/.test(text)) {
    // Looks like a proper product/brand name — check it's not plain English
    // Plain English words are lowercase-dominant and longer
    const wordCount = text.split(' ').length;
    const allWordsCapitalised = text.split(' ').every(w => /^[A-Z]/.test(w));
    const hasNumber = /\d/.test(text);
    const hasSymbol = /[®™&]/.test(text);

    // Short capitalised labels or ones with numbers/symbols → PROTECT
    if (wordCount <= 3 && (allWordsCapitalised || hasNumber || hasSymbol)) {
      // Exclude plain English short phrases like "Our Community of"
      // Rule: if it's inside an <a> tag it's almost certainly a nav label → PROTECT
      if (parentTag === 'a')  return 'PROTECT';
      // If it's a known short tech/product shape: one or two capitalised words, no verb
      const hasVerb = /\b(is|are|was|were|be|been|have|has|had|do|does|did|will|would|can|could|should|may|might|shall|must|need|dare|ought|used)\b/i.test(text);
      if (!hasVerb && wordCount <= 2) return 'PROTECT';
    }
  }

  // 6. Email addresses
  if (/^[\w.+-]+@[\w-]+\.[a-z]{2,}$/i.test(text)) return 'PROTECT';

  // 7. Phone numbers
  if (/^[+\d\s\-().]{7,}$/.test(text) && /\d{5,}/.test(text)) return 'PROTECT';

  return 'TRANSLATE';
}

// ── Walk every text node in <body> ──
const entries = [];

$('body *').contents().each(function () {
  const parent    = this.parent;
  const parentTag = parent && parent.name ? parent.name.toLowerCase() : '';

  if (SKIP_TAGS.has(parentTag)) return;
  if (this.type !== 'text')     return;

  const raw = this.data || '';
  if (!raw.trim()) return;

  const text = raw.replace(/\s+/g, ' ').trim();
  if (!text) return;

  // <a> handling — include internal nav links, skip external/email
  if (parentTag === 'a') {
    const href = (parent.attribs && parent.attribs.href)  || '';
    const cls  = (parent.attribs && parent.attribs.class) || '';
    if (
      href.startsWith('http')   ||
      href.startsWith('mailto') ||
      href.startsWith('//')     ||
      cls.includes('__cf_email__')
    ) return;
  }

  const flag = getFlag(text, parentTag);
  entries.push({ flag, text });
});

// ── Auto-build protect list for dynamic prompt injection ──
const protectedItems = [...new Set(
  entries
    .filter(e => e.flag === 'PROTECT')
    .map(e => e.text)
)];

// ── Build numbered output: N|||FLAG:::text ──
const numbered = entries
  .map((e, i) => `${i + 1}|||${e.flag}:::${e.text}`)
  .join('\n');

return {
  json: {
    filePath:      $json.filePath,
    originalHtml:  html,
    textOnly:      numbered,
    lineCount:     entries.length,
    protectedList: protectedItems.join(' | '),  // passed into prompt dynamically
  },
  binary: item.binary,
};
